const body = $input.first().json.body || $input.first().json;

const product = {
  id:          body.product_id,
  title:       body.product_title,
  type:        body.product_type,
  pdf_url:     body.pdf_url,
  pdf_path:    body.pdf_path,
  page_count:  body.page_count,
  pages:       body.pages_breakdown || [],
  // Brand
  brand:       'ClearStack Studio',
  website:     'clearstackstudio.com',
  primary:     '#1B2A4A',
  accent:      '#C9A84C',
  // Mockup output paths
  mockup_dir:  `/tmp/mockups/${body.product_id}`
};

// 10 mockup types — Etsy allows 10 images per listing
// Each mockup serves a specific conversion purpose
const mockupPlan = [
  {
    id: 'hero',
    slot: 1,
    purpose: 'Hero — first thing buyer sees. Product name on clean background.',
    style: 'text_overlay_clean',
    priority: 'critical'
  },
  {
    id: 'mockup_desk',
    slot: 2,
    purpose: 'Lifestyle — planner on a desk with coffee/pen context',
    style: 'device_frame_a4_desk',
    priority: 'critical'
  },
  {
    id: 'pages_preview',
    slot: 3,
    purpose: 'Content preview — shows actual pages inside the planner',
    style: 'pages_spread',
    priority: 'critical'
  },
  {
    id: 'whats_included',
    slot: 4,
    purpose: 'What is included — lists all sections and page types',
    style: 'feature_list',
    priority: 'critical'
  },
  {
    id: 'how_to_use',
    slot: 5,
    purpose: 'How to use — 3 steps: download, print, use',
    style: 'steps_graphic',
    priority: 'high'
  },
  {
    id: 'close_up_1',
    slot: 6,
    purpose: 'Close-up of weekly spread or key page',
    style: 'page_closeup',
    priority: 'high'
  },
  {
    id: 'close_up_2',
    slot: 7,
    purpose: 'Close-up of monthly or goal page',
    style: 'page_closeup_2',
    priority: 'medium'
  },
  {
    id: 'value_prop',
    slot: 8,
    purpose: 'Value proposition — key benefit in large text',
    style: 'quote_card',
    priority: 'medium'
  },
  {
    id: 'instant_download',
    slot: 9,
    purpose: 'Trust signal — instant download badge, format info',
    style: 'trust_badge',
    priority: 'medium'
  },
  {
    id: 'brand_closer',
    slot: 10,
    purpose: 'Brand closer — ClearStack Studio branding, shop name',
    style: 'brand_card',
    priority: 'low'
  }
];

return [{ json: {
  product,
  mockup_plan: mockupPlan,
  critical_mockups: mockupPlan.filter(m => m.priority === 'critical'),
  all_mockups: mockupPlan,
  original_data: body
}}];

const uploadOutput = $input.first().json.stdout || '';
const config = $('⚙️ Plan Mockup Set').first().json;

// Parse all mockup URLs
const baseUrlMatch = uploadOutput.match(/BASE_URL=(.+)/);
const baseUrl = baseUrlMatch ? baseUrlMatch[1].trim() : '';

const mockupUrls = [];
const urlMatches = uploadOutput.matchAll(/MOCKUP_URL=(.+)/g);
for (const match of urlMatches) {
  mockupUrls.push(match[1].trim());
}

const totalMockups = parseInt((uploadOutput.match(/TOTAL_MOCKUPS=(\d+)/) || [])[1] || '0');

if (mockupUrls.length === 0) {
  return [{ json: {
    error: true,
    message: 'No mockup URLs found',
    upload_output: uploadOutput
  }}];
}

// Sort mockups by filename (01, 02, 03...)
mockupUrls.sort();

const result = {
  product_id: config.product.id,
  product_title: config.product.title,
  product_type: config.product.type,
  pdf_url: config.product.pdf_url,
  mockup_urls: mockupUrls,
  mockup_count: totalMockups,
  hero_image_url: mockupUrls[0] || '',
  listing_images: mockupUrls,
  generated_at: new Date().toISOString(),
  _ready_for_publishing: true
};

console.log(`${totalMockups} mockups ready for: ${config.product.title}`);
return [{ json: result }];
